import json
import logging
from typing import Any, Dict

logger = logging.getLogger()
logger.setLevel(logging.INFO)


def process_action(action: Dict[str, Any]) -> Dict[str, Any]:
    action_type = action.get("type", "unknown")
    user_id = action.get("user_id")
    metadata = action.get("metadata", {})

    return {
        "status": "processed",
        "type": action_type,
        "user_id": user_id,
        "metadata": metadata,
    }


def lambda_handler(event, context):
    try:
        body = event.get("body", "{}")
        if event.get("isBase64Encoded"):
            import base64
            body = base64.b64decode(body).decode("utf-8")

        if isinstance(body, str):
            payload = json.loads(body)
        elif isinstance(body, dict):
            payload = body
        else:
            raise ValueError("Unsupported body format")

        actions = payload.get("actions", [])
        if not isinstance(actions, list):
            raise ValueError("Field 'actions' must be a list")

        results = [process_action(action) for action in actions]

        response_body = {
            "message": "Webhook processed successfully",
            "processed_count": len(results),
            "results": results,
        }

        return {
            "statusCode": 200,
            "headers": {"Content-Type": "application/json"},
            "body": json.dumps(response_body),
        }

    except json.JSONDecodeError:
        logger.exception("Invalid JSON payload")
        return {
            "statusCode": 400,
            "headers": {"Content-Type": "application/json"},
            "body": json.dumps({"message": "Invalid JSON payload"}),
        }
    except Exception as exc:
        logger.exception("Error processing webhook")
        return {
            "statusCode": 500,
            "headers": {"Content-Type": "application/json"},
            "body": json.dumps({"message": "Internal server error", "error": str(exc)}),
        }